import { describe, it, expect } from "vitest";
import { claimOffice } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // =====================================================
  // QUOTE: Base premiums for individual items
  // =====================================================

  describe("quote — base premiums for individual items", () => {
    it.todo(
      "should return premium 105 G for a single sword (100 base + 5 fee)"
    );

    it.todo(
      "should return premium 65 G for a single amulet (60 base + 5 fee)"
    );

    it.todo(
      "should return premium 85 G for a single staff (80 base + 5 fee)"
    );

    it.todo(
      "should return premium 45 G for a single potion (40 base + 5 fee)"
    );

    it.todo(
      "should return premium 30 G for a single rune component (25 base + 5 fee)"
    );

    it.todo(
      "should return premium 30 G for a single moonstone component (25 base + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Building block of 3 alike components
  // =====================================================

  describe("quote — building block of 3 alike components", () => {
    it.todo(
      "should return 55 G for 2 runes (50 base, no block + 5 fee)"
    );

    it.todo(
      "should return 65 G for 3 runes (60 base, block applies + 5 fee)"
    );

    it.todo(
      "should return 105 G for 4 runes (100 base, no block — block requires exactly 3 + 5 fee)"
    );

    it.todo(
      "should return 180 G for 7 runes (175 base, no block possible + 5 fee)"
    );

    it.todo(
      "should return 80 G for 2 runes + 1 moonstone (75 base, no block: different types + 5 fee)"
    );

    it.todo(
      "should return 125 G for 3 runes + 3 moonstones (120 base, two separate blocks + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Processing fee
  // =====================================================

  describe("quote — processing fee", () => {
    it.todo(
      "should return premium 5 G for an empty item list (only processing fee)"
    );
  });

  // =====================================================
  // QUOTE: Cursed item surcharge (item-specific modifier)
  // =====================================================

  describe("quote — cursed item surcharge", () => {
    it.todo(
      "should add 50% risk surcharge for a cursed sword — premium 155 G (100 base + 50 curse + 5 fee)"
    );

    it.todo(
      "should not add cursed surcharge for a non-cursed sword — premium 105 G (100 base + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: High enchantment surcharge (item-specific modifier)
  // =====================================================

  describe("quote — high enchantment surcharge", () => {
    it.todo(
      "should add 30% surcharge for sword with enchantment 5 — premium 135 G (100 base + 30 enchantment + 5 fee)"
    );

    it.todo(
      "should not add enchantment surcharge for sword with enchantment 4 — premium 105 G (100 base + 5 fee)"
    );

    it.todo(
      "should add 30% surcharge for sword with enchantment 9 — premium 135 G (100 base + 30 enchantment + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Combined item-specific modifiers (cursed + high enchantment)
  // =====================================================

  describe("quote — combined item-specific modifiers", () => {
    it.todo(
      "should apply both cursed and enchantment surcharges for cursed sword with enchantment 5 — premium 185 G (100 base + 50 curse + 30 enchantment + 5 fee)"
    );

    it.todo(
      "should apply only curse surcharge for cursed sword with enchantment 4 — premium 155 G (100 base + 50 curse + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Modifier scope on multi-item policies
  // =====================================================

  describe("quote — modifier scope on multi-item policies", () => {
    it.todo(
      "should apply cursed surcharge only to the cursed item — cursed sword + plain amulet = 215 G (100 + 60 base + 50 curse on sword + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Policy-wide modifiers — loyalty discount
  // =====================================================

  describe("quote — loyalty discount", () => {
    it.todo(
      "should apply 20% loyalty discount for customer with exactly 2 years — sword premium 85 G (100 base - 20 loyalty + 5 fee)"
    );

    it.todo(
      "should apply 20% loyalty discount for customer with 3 years — sword premium 85 G (100 base - 20 loyalty + 5 fee)"
    );

    it.todo(
      "should not apply loyalty discount for customer with 1 year — sword premium 105 G (100 base + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Policy-wide modifiers — first insurance surcharge
  // =====================================================

  describe("quote — first insurance surcharge", () => {
    it.todo(
      "should apply 10% first insurance surcharge on policy base premium — sword premium 115 G (100 base + 10 first insurance + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Policy-wide modifiers — follow-up contract discount
  // =====================================================

  describe("quote — follow-up contract discount", () => {
    it.todo(
      "should apply 15% follow-up discount on second quote — sword on second quote = 90 G (100 base - 15 follow-up + 5 fee)"
    );
  });

  // =====================================================
  // QUOTE: Rounding in MHPCO's favor
  // =====================================================

  describe("quote — rounding premiums up", () => {
    it.todo(
      "should round premium up when calculation yields a fraction — e.g. 197.5 G rounds to 198 G"
    );
  });

  // =====================================================
  // QUOTE: Integration example — newcomer with cursed sword
  // =====================================================

  describe("quote — integration: newcomer with cursed sword", () => {
    it.todo(
      "should return 165 G for newcomer (0 years, no previous contract) with cursed sword (steel, enchantment 3) — (100 base + 50 curse + 10 first insurance = 160 + 5 fee = 165)"
    );
  });

  // =====================================================
  // QUOTE: Integration example — long-standing customer second contract
  // =====================================================

  describe("quote — integration: long-standing customer second contract", () => {
    it.todo(
      "should return 160 G for 3-year customer on second quote with cursed sword (steel, enchantment 7) — (100 base + 50 curse + 30 enchant - 20 loyalty + 10 first insurance - 15 follow-up = 155 + 5 fee = 160)"
    );
  });

  // =====================================================
  // QUOTE: Edge cases / errors
  // =====================================================

  describe("quote — edge cases", () => {
    it.todo(
      "should reject unknown item type (e.g. 'broomstick') with non-zero exit and error to stderr"
    );
  });

  // =====================================================
  // CLAIM: Standard reimbursement (no special clauses)
  // =====================================================

  describe("claim — standard reimbursement", () => {
    it.todo(
      "should return payout 400 G for regular sword (steel, enchantment 3) with 500 G damage — full reimbursement minus 100 G deductible"
    );

    it.todo(
      "should return payout 100 G for rune with 200 G damage — full reimbursement minus 100 G deductible"
    );
  });

  // =====================================================
  // CLAIM: Deductible per damage event
  // =====================================================

  describe("claim — deductible per damage event", () => {
    it.todo(
      "should apply 100 G deductible per damaged item — sword 500 G + amulet 300 G = payout 600 G (deductible applied once per item)"
    );
  });

  // =====================================================
  // CLAIM: Enchantment >= 8 reimbursement at 50%
  // =====================================================

  describe("claim — high enchantment reimbursement", () => {
    it.todo(
      "should reimburse at 50% for steel sword with enchantment 9, damage 1000 G — payout 400 G (500 - 100 deductible)"
    );
  });

  // =====================================================
  // CLAIM: Dragon material — full reimbursement
  // =====================================================

  describe("claim — dragon material reimbursement", () => {
    it.todo(
      "should fully reimburse dragon-material sword with enchantment 5, damage 800 G — payout 700 G (800 - 100 deductible)"
    );
  });

  // =====================================================
  // CLAIM: Both clauses — enchantment >= 8 AND dragon material
  // =====================================================

  describe("claim — enchantment >= 8 AND dragon material", () => {
    it.todo(
      "should apply 50% rule when both clauses apply — dragon-material sword enchantment 9, damage 1000 G — payout 400 G (50% wins: 500 - 100)"
    );

    it.todo(
      "should apply 50% rule for dragon-material sword with exactly enchantment 8, damage 1000 G — payout 400 G (50% first: 500 - 100)"
    );
  });

  // =====================================================
  // CLAIM: Rounding payouts down
  // =====================================================

  describe("claim — rounding payouts down", () => {
    it.todo(
      "should round payout down when calculation yields a fraction — e.g. 350.5 G rounds to 350 G"
    );
  });

  // =====================================================
  // CLAIM: Multiple items of the same type
  // =====================================================

  describe("claim — multiple items of the same type", () => {
    it.todo(
      "should treat each damage entry as separate with its own deductible — two swords insured, both damaged"
    );

    it.todo(
      "should reject claim when damages contain more entries of a type than insured — two sword damages but only one sword insured"
    );
  });

  // =====================================================
  // CLAIM: Cap (2x insurance sum)
  // =====================================================

  describe("claim — cap", () => {
    it.todo(
      "should cap total payout at 2x insurance sum — sword + amulet = insurance sum 1600 G, cap 3200 G"
    );

    it.todo(
      "should base cap on unmodified insurance value — cursed sword cap is 2000 G (2 x 1000), not affected by premium modifiers"
    );

    it.todo(
      "should base insurance sum on item count not block discount — sword + 3 runes = insurance sum 1750 G (1000 + 3x250)"
    );
  });

  // =====================================================
  // CLAIM: Cap exhaustion over successive claims
  // =====================================================

  describe("claim — cap exhaustion over successive claims", () => {
    it.todo(
      "should return payout 1400 G and remainingCap 600 G on first claim of 1500 G damage against sword (cap 2000 G)"
    );

    it.todo(
      "should return payout 600 G and remainingCap 0 G on second claim of 1500 G damage when only 600 G cap remains"
    );
  });

  // =====================================================
  // CLAIM: Edge cases / errors
  // =====================================================

  describe("claim — edge cases", () => {
    it.todo(
      "should reject claim for item not in policy — amulet damaged when only sword insured"
    );

    it.todo(
      "should reject claim with negative damage amount — amount: -200"
    );
  });

  // =====================================================
  // CLI: input/output format
  // =====================================================

  describe("CLI — input/output format", () => {
    it.todo(
      "should read JSON from stdin and write JSON results to stdout with correct shape"
    );

    it.todo(
      "should process sequential steps where claim references earlier quote by zero-based step index"
    );

    it.todo(
      "should exit with non-zero status and write error to stderr for unknown item type"
    );

    it.todo(
      "should exit with non-zero status and write error to stderr for claim referencing item not in policy"
    );

    it.todo(
      "should exit with non-zero status and write error to stderr for negative damage amount"
    );
  });
});
